let cart = ['apple', 'bread', 'milk'];

console.log('Initial:', cart);

cart.push('cheese');  // Add to end
console.log('After push:', cart);

cart.pop();  // Remove from end
console.log('After pop:', cart);

let queue = ['Alice', 'Bob', 'Charlie'];

console.log('Queue:', queue);

queue.shift();  // Remove first person
console.log('Next person served:', queue[0]);

queue.unshift('Diana');  // Add person to front
console.log('New queue:', queue);

let items = ['do', 'a', 'barrel', 'roll'];

console.log('Items:', items);
console.log('Joined:', items.join(' '));

items.reverse();
console.log('Reversed:', items);
console.log('Reversed string:', items.join('-'));
